<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Snake</title>
<style>
  :root {
    --bg: #0d1117;
    --panel: #161b22;
    --border: #30363d;
    --accent: #39d353;
    --accent-dim: #2ea043;
    --food: #f85149;
    --text: #e6edf3;
    --muted: #8b949e;
  }
  * { box-sizing: border-box; }
  html, body {
    margin: 0;
    padding: 0;
    min-height: 100vh;
    background: radial-gradient(1200px 800px at 50% -10%, #1b2230 0%, var(--bg) 60%);
    color: var(--text);
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
    display: flex;
    align-items: center;
    justify-content: center;
  }
  .wrap {
    display: flex;
    gap: 28px;
    align-items: flex-start;
    padding: 24px;
    flex-wrap: wrap;
    justify-content: center;
  }
  .stage {
    position: relative;
    padding: 14px;
    background: var(--panel);
    border: 1px solid var(--border);
    border-radius: 14px;
    box-shadow: 0 20px 60px rgba(0,0,0,0.5), inset 0 0 0 1px rgba(255,255,255,0.02);
  }
  #snake {
    display: block;
    background: #0a0e14;
    border-radius: 8px;
    image-rendering: pixelated;
    width: 480px;
    height: 480px;
  }
  .overlay {
    position: absolute;
    inset: 14px;
    border-radius: 8px;
    display: flex;
    align-items: center;
    justify-content: center;
    pointer-events: none;
    font-size: 30px;
    font-weight: 700;
    letter-spacing: 2px;
    text-shadow: 0 2px 20px rgba(0,0,0,0.8);
    opacity: 0;
    transition: opacity 0.2s ease;
  }
  .overlay.show { opacity: 1; }
  .overlay.dead { color: var(--food); }
  .overlay.idle { color: var(--muted); font-size: 22px; }
  .overlay.paused { color: #58a6ff; }
  .panel {
    width: 220px;
    display: flex;
    flex-direction: column;
    gap: 16px;
  }
  .scorebox {
    background: var(--panel);
    border: 1px solid var(--border);
    border-radius: 12px;
    padding: 16px 18px;
  }
  .scorebox .label {
    font-size: 11px;
    text-transform: uppercase;
    letter-spacing: 2px;
    color: var(--muted);
  }
  #score {
    font-size: 40px;
    font-weight: 800;
    color: var(--accent);
    line-height: 1.1;
    font-variant-numeric: tabular-nums;
  }
  .meta {
    font-size: 12px;
    color: var(--muted);
    margin-top: 8px;
    display: flex;
    justify-content: space-between;
  }
  .controls {
    display: grid;
    grid-template-columns: 1fr 1fr;
    gap: 8px;
  }
  .controls .full { grid-column: 1 / -1; }
  button {
    appearance: none;
    border: 1px solid var(--border);
    background: #21262d;
    color: var(--text);
    padding: 11px 12px;
    border-radius: 9px;
    font-size: 14px;
    font-weight: 600;
    cursor: pointer;
    transition: transform 0.05s ease, background 0.15s ease, border-color 0.15s ease;
  }
  button:hover { background: #2d333b; border-color: #444c56; }
  button:active { transform: translateY(1px); }
  button.primary {
    background: var(--accent-dim);
    border-color: var(--accent-dim);
    color: #fff;
  }
  button.primary:hover { background: var(--accent); border-color: var(--accent); }
  .help {
    font-size: 12px;
    color: var(--muted);
    line-height: 1.6;
    background: var(--panel);
    border: 1px solid var(--border);
    border-radius: 12px;
    padding: 14px 16px;
  }
  .help kbd {
    background: #21262d;
    border: 1px solid var(--border);
    border-bottom-width: 2px;
    border-radius: 4px;
    padding: 1px 6px;
    font-size: 11px;
    color: var(--text);
    font-family: ui-monospace, SFMono-Regular, Menlo, monospace;
  }
  h1 {
    margin: 0 0 4px;
    font-size: 20px;
    letter-spacing: 1px;
  }
  .subtitle { color: var(--muted); font-size: 12px; margin: 0 0 4px; }
</style>
</head>
<body>
  <div class="wrap">
    <div class="stage">
      <canvas id="snake" width="480" height="480"></canvas>
      <div class="overlay idle show" id="overlay">Press Start</div>
    </div>
    <div class="panel">
      <div>
        <h1>SNAKE</h1>
        <p class="subtitle">Eat. Grow. Don't bite yourself.</p>
      </div>
      <div class="scorebox">
        <div class="label">Score</div>
        <div id="score">0</div>
        <div class="meta">
          <span id="lenLabel">len 3</span>
          <span id="statusLabel">idle</span>
        </div>
      </div>
      <div class="controls">
        <button id="start" class="primary full">Start</button>
        <button id="pause">Pause</button>
        <button id="reset">Reset</button>
      </div>
      <div class="help">
        Steer with <kbd>↑</kbd> <kbd>↓</kbd> <kbd>←</kbd> <kbd>→</kbd>.
        You can't reverse directly into yourself. Walls are deadly.
      </div>
    </div>
  </div>

<script>
(function () {
  const canvas = document.getElementById('snake');
  const ctx = canvas.getContext('2d');
  const scoreEl = document.getElementById('score');
  const lenEl = document.getElementById('lenLabel');
  const statusEl = document.getElementById('statusLabel');
  const overlay = document.getElementById('overlay');

  const W = 20;          // cells across (>=10)
  const H = 20;          // cells down (>=10)
  const CELL = canvas.width / W;   // 24px per cell

  const DIRS = {
    up:    [0, -1],
    down:  [0,  1],
    left:  [-1, 0],
    right: [1,  0],
  };
  const OPPOSITE = { up: 'down', down: 'up', left: 'right', right: 'left' };

  const state = {
    snake: [],          // head first, array of [x,y]
    dir: 'right',
    nextDir: 'right',
    food: [0, 0],
    alive: true,
    score: 0,
    running: false,
    timer: null,
    speed: 110,         // ms per tick
  };

  function reset() {
    state.snake = [[8, 10], [7, 10], [6, 10]]; // head first, length 3
    state.dir = 'right';
    state.nextDir = 'right';
    state.alive = true;
    state.score = 0;
    placeFood();
    stop();
    draw();
    updateHud();
    showOverlay('Press Start', 'idle');
  }

  function placeFood() {
    const occupied = new Set(state.snake.map(p => p[0] + ',' + p[1]));
    const free = [];
    for (let y = 0; y < H; y++) {
      for (let x = 0; x < W; x++) {
        if (!occupied.has(x + ',' + y)) free.push([x, y]);
      }
    }
    if (free.length === 0) {
      // board full — win condition; keep food where it is
      return;
    }
    state.food = free[Math.floor(Math.random() * free.length)];
  }

  function setFood(x, y) {
    if (typeof x !== 'number' || typeof y !== 'number') return;
    if (x < 0 || x >= W || y < 0 || y >= H) return;
    state.food = [x, y];
    draw();
  }

  function setDir(d) {
    if (!DIRS[d]) return;
    if (!state.alive) return;
    // 180° reversal relative to current heading is ignored
    if (OPPOSITE[d] === state.dir) return;
    state.nextDir = d;
  }

  function tick() {
    if (!state.alive) return;

    // commit queued direction (already filtered against reversals)
    state.dir = state.nextDir;
    const [dx, dy] = DIRS[state.dir];
    const head = state.snake[0];
    const nx = head[0] + dx;
    const ny = head[1] + dy;

    // wall collision
    if (nx < 0 || nx >= W || ny < 0 || ny >= H) {
      state.alive = false;
      stop();
      draw();
      updateHud();
      showOverlay('Game Over', 'dead');
      return;
    }

    const growing = (nx === state.food[0] && ny === state.food[1]);

    // self collision: when not growing, the tail cell will vacate, so it's safe
    const checkBody = growing
      ? state.snake
      : state.snake.slice(0, state.snake.length - 1);

    for (let i = 0; i < checkBody.length; i++) {
      if (checkBody[i][0] === nx && checkBody[i][1] === ny) {
        state.alive = false;
        stop();
        draw();
        updateHud();
        showOverlay('Game Over', 'dead');
        return;
      }
    }

    state.snake.unshift([nx, ny]);
    if (growing) {
      state.score += 1;
      placeFood();
    } else {
      state.snake.pop();
    }

    draw();
    updateHud();
  }

  function start() {
    if (!state.alive) reset();
    if (state.running) return;
    state.running = true;
    hideOverlay();
    state.timer = setInterval(tick, state.speed);
    updateHud();
  }

  function pause() {
    if (!state.running) return;
    state.running = false;
    clearInterval(state.timer);
    state.timer = null;
    showOverlay('Paused', 'paused');
    updateHud();
  }

  function stop() {
    state.running = false;
    if (state.timer) clearInterval(state.timer);
    state.timer = null;
  }

  function showOverlay(text, cls) {
    overlay.textContent = text;
    overlay.className = 'overlay show ' + (cls || '');
  }
  function hideOverlay() {
    overlay.className = 'overlay';
  }

  function updateHud() {
    scoreEl.textContent = state.score;
    lenEl.textContent = 'len ' + state.snake.length;
    if (!state.alive) statusEl.textContent = 'dead';
    else if (state.running) statusEl.textContent = 'running';
    else statusEl.textContent = 'idle';
  }

  // ---------- Rendering ----------
  function draw() {
    const g = ctx;
    // background
    g.fillStyle = '#0a0e14';
    g.fillRect(0, 0, canvas.width, canvas.height);

    // subtle grid
    g.strokeStyle = 'rgba(255,255,255,0.035)';
    g.lineWidth = 1;
    for (let x = 0; x <= W; x++) {
      g.beginPath();
      g.moveTo(x * CELL + 0.5, 0);
      g.lineTo(x * CELL + 0.5, canvas.height);
      g.stroke();
    }
    for (let y = 0; y <= H; y++) {
      g.beginPath();
      g.moveTo(0, y * CELL + 0.5);
      g.lineTo(canvas.width, y * CELL + 0.5);
      g.stroke();
    }

    // food (pulsing-ish via gradient)
    const [fx, fy] = state.food;
    drawFood(fx, fy);

    // snake
    const n = state.snake.length;
    for (let i = n - 1; i >= 0; i--) {
      const [sx, sy] = state.snake[i];
      const isHead = (i === 0);
      drawSegment(sx, sy, isHead, i, n);
    }
  }

  function drawFood(x, y) {
    const cx = x * CELL + CELL / 2;
    const cy = y * CELL + CELL / 2;
    const r = CELL * 0.34;
    const g = ctx;
    // glow
    const grad = g.createRadialGradient(cx, cy, 1, cx, cy, CELL * 0.9);
    grad.addColorStop(0, 'rgba(248,81,73,0.55)');
    grad.addColorStop(1, 'rgba(248,81,73,0)');
    g.fillStyle = grad;
    g.fillRect(x * CELL - CELL/2, y * CELL - CELL/2, CELL * 2, CELL * 2);
    // core
    g.fillStyle = '#ff6b60';
    g.beginPath();
    g.arc(cx, cy, r, 0, Math.PI * 2);
    g.fill();
    g.fillStyle = 'rgba(255,255,255,0.85)';
    g.beginPath();
    g.arc(cx - r * 0.3, cy - r * 0.3, r * 0.28, 0, Math.PI * 2);
    g.fill();
  }

  function drawSegment(x, y, isHead, idx, total) {
    const g = ctx;
    const pad = 2;
    const px = x * CELL + pad;
    const py = y * CELL + pad;
    const size = CELL - pad * 2;
    const r = 6;

    // color gradient from head (bright) to tail (dim)
    const t = total <= 1 ? 0 : idx / (total - 1);
    if (isHead) {
      g.fillStyle = state.alive ? '#4ade80' : '#f85149';
    } else {
      const head = [57, 211, 83];   // #39d353
      const tail = [30, 120, 50];
      const c = head.map((h, i) => Math.round(h + (tail[i] - h) * t));
      g.fillStyle = state.alive
        ? `rgb(${c[0]},${c[1]},${c[2]})`
        : `rgb(${120 + t*40|0},${40},${40})`;
    }
    roundRect(g, px, py, size, size, r);
    g.fill();

    // head eyes
    if (isHead) {
      const [dx, dy] = DIRS[state.dir];
      const cx = x * CELL + CELL / 2;
      const cy = y * CELL + CELL / 2;
      const off = CELL * 0.18;
      const perp = CELL * 0.18;
      // two eyes perpendicular to motion
      const ex1 = cx + dx * off + (-dy) * perp;
      const ey1 = cy + dy * off + (dx) * perp;
      const ex2 = cx + dx * off - (-dy) * perp;
      const ey2 = cy + dy * off - (dx) * perp;
      g.fillStyle = '#0a0e14';
      g.beginPath(); g.arc(ex1, ey1, CELL * 0.09, 0, Math.PI * 2); g.fill();
      g.beginPath(); g.arc(ex2, ey2, CELL * 0.09, 0, Math.PI * 2); g.fill();
    }
  }

  function roundRect(g, x, y, w, h, r) {
    r = Math.min(r, w / 2, h / 2);
    g.beginPath();
    g.moveTo(x + r, y);
    g.arcTo(x + w, y, x + w, y + h, r);
    g.arcTo(x + w, y + h, x, y + h, r);
    g.arcTo(x, y + h, x, y, r);
    g.arcTo(x, y, x + w, y, r);
    g.closePath();
  }

  // ---------- Input ----------
  window.addEventListener('keydown', (e) => {
    const map = {
      ArrowUp: 'up', ArrowDown: 'down', ArrowLeft: 'left', ArrowRight: 'right',
      w: 'up', s: 'down', a: 'left', d: 'right',
      W: 'up', S: 'down', A: 'left', D: 'right',
    };
    if (map[e.key]) {
      e.preventDefault();
      setDir(map[e.key]);
      // auto-start on first directional key if idle & alive
      if (!state.running && state.alive) start();
    } else if (e.key === ' ') {
      e.preventDefault();
      if (state.running) pause(); else start();
    } else if (e.key === 'r' || e.key === 'R') {
      reset();
    }
  });

  document.getElementById('start').addEventListener('click', start);
  document.getElementById('pause').addEventListener('click', pause);
  document.getElementById('reset').addEventListener('click', reset);

  // ---------- Public API ----------
  window.game = {
    w: W,
    h: H,
    reset: reset,
    tick: tick,
    setDir: setDir,
    setFood: setFood,
    snake: () => state.snake.map(p => [p[0], p[1]]),
    food: () => [state.food[0], state.food[1]],
    alive: () => state.alive,
    score: () => state.score,
  };

  // init
  reset();
})();
</script>
</body>
</html>
